using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Store.Tests;

[TestClass]
public sealed class ShoppingCartTests
{
    private ShoppingCart _sut = null!;

    [TestInitialize]
    public void Setup() => _sut = new ShoppingCart();

    // ── AddItem ──────────────────────────────────────────────

    [TestMethod]
    public void AddItem_SingleItem_IncreasesItemCount()
    {
        _sut.AddItem("SKU-001", 2, 9.99m);

        Assert.AreEqual(1, _sut.ItemCount);
    }

    [TestMethod]
    public void AddItem_MultipleDistinctItems_TracksEach()
    {
        _sut.AddItem("A", 1, 5m);
        _sut.AddItem("B", 1, 10m);

        Assert.AreEqual(2, _sut.ItemCount);
    }

    [TestMethod]
    public void AddItem_DuplicateSku_MergesQuantity()
    {
        _sut.AddItem("A", 2, 5m);
        _sut.AddItem("A", 3, 5m);

        Assert.AreEqual(1, _sut.ItemCount);
        Assert.AreEqual(25m, _sut.CalculateTotal()); // 5 × $5
    }

    [TestMethod]
    public void AddItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _sut.AddItem(null!, 1, 5m));
    }

    [TestMethod]
    [DataRow(0, DisplayName = "Zero quantity")]
    [DataRow(-1, DisplayName = "Negative quantity")]
    public void AddItem_InvalidQuantity_ThrowsArgumentOutOfRangeException(int qty)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() => _sut.AddItem("A", qty, 5m));
    }

    [TestMethod]
    public void AddItem_NegativePrice_ThrowsArgumentOutOfRangeException()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(() => _sut.AddItem("A", 1, -1m));
    }

    [TestMethod]
    public void AddItem_ZeroPrice_Succeeds()
    {
        _sut.AddItem("FREE", 1, 0m);

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    // ── RemoveItem ───────────────────────────────────────────

    [TestMethod]
    public void RemoveItem_ExistingItem_RemovesFromCart()
    {
        _sut.AddItem("A", 1, 10m);
        _sut.RemoveItem("A");

        Assert.AreEqual(0, _sut.ItemCount);
    }

    [TestMethod]
    public void RemoveItem_NonExistentSku_ThrowsKeyNotFoundException()
    {
        Assert.ThrowsException<KeyNotFoundException>(() => _sut.RemoveItem("MISSING"));
    }

    [TestMethod]
    public void RemoveItem_NullSku_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _sut.RemoveItem(null!));
    }

    [TestMethod]
    public void RemoveItem_OnlyRemovesTargetItem()
    {
        _sut.AddItem("A", 1, 5m);
        _sut.AddItem("B", 1, 10m);
        _sut.RemoveItem("A");

        Assert.AreEqual(1, _sut.ItemCount);
        Assert.AreEqual(10m, _sut.CalculateTotal());
    }

    // ── CalculateTotal ───────────────────────────────────────

    [TestMethod]
    public void CalculateTotal_EmptyCart_ReturnsZero()
    {
        Assert.AreEqual(0m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_MultipleItems_ReturnsSumOfLineItems()
    {
        _sut.AddItem("A", 2, 10m);  // 20
        _sut.AddItem("B", 3, 5m);   // 15

        Assert.AreEqual(35m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void CalculateTotal_AfterRemoval_ExcludesRemovedItem()
    {
        _sut.AddItem("A", 1, 100m);
        _sut.AddItem("B", 1, 50m);
        _sut.RemoveItem("A");

        Assert.AreEqual(50m, _sut.CalculateTotal());
    }

    // ── ApplyCoupon ──────────────────────────────────────────

    [TestMethod]
    [DataRow("SAVE10", 10, DisplayName = "SAVE10 = 10% off")]
    [DataRow("SAVE20", 20, DisplayName = "SAVE20 = 20% off")]
    [DataRow("HALF", 50, DisplayName = "HALF = 50% off")]
    public void ApplyCoupon_ValidCode_AppliesDiscount(string code, int discountPct)
    {
        _sut.AddItem("A", 1, 100m);
        _sut.ApplyCoupon(code);

        Assert.AreEqual(100m - discountPct, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_CaseInsensitive_AppliesDiscount()
    {
        _sut.AddItem("A", 1, 100m);
        _sut.ApplyCoupon("save10");

        Assert.AreEqual(90m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_InvalidCode_ThrowsArgumentException()
    {
        Assert.ThrowsException<ArgumentException>(() => _sut.ApplyCoupon("BOGUS"));
    }

    [TestMethod]
    public void ApplyCoupon_NullCode_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() => _sut.ApplyCoupon(null!));
    }

    [TestMethod]
    public void ApplyCoupon_ReplacedByNewCoupon_UsesLatest()
    {
        _sut.AddItem("A", 1, 100m);
        _sut.ApplyCoupon("SAVE10");
        _sut.ApplyCoupon("SAVE20");

        Assert.AreEqual(80m, _sut.CalculateTotal());
    }

    [TestMethod]
    public void ApplyCoupon_OnEmptyCart_TotalRemainsZero()
    {
        _sut.ApplyCoupon("HALF");

        Assert.AreEqual(0m, _sut.CalculateTotal());
    }
}

